#include <stdio.h>
#include <string.h>

int longestPalSubseq(const char *s) {
    int n = strlen(s);
    static int dp[1000][1000]; // static to avoid stack overflow
    for (int i = n - 1; i >= 0; --i) {
        dp[i][i] = 1;
        for (int j = i + 1; j < n; ++j) {
            if (s[i] == s[j]) {
                if (j == i + 1) dp[i][j] = 2;
                else dp[i][j] = 2 + dp[i + 1][j - 1];
            } else {
                dp[i][j] = dp[i + 1][j] > dp[i][j - 1] ? dp[i + 1][j] : dp[i][j - 1];
            }
        }
    }
    return dp[0][n - 1];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[1001];
        scanf("%1000s", s);
        printf("%d\n", longestPalSubseq(s));
    }
    return 0;
}

