import sys

def longest_pal_subseq(s: str) -> int:
    n = len(s)
    dp = [[0] * n for _ in range(n)]
    for i in range(n - 1, -1, -1):
        dp[i][i] = 1
        for j in range(i + 1, n):
            if s[i] == s[j]:
                dp[i][j] = 2 + (dp[i + 1][j - 1] if i + 1 <= j - 1 else 0)
            else:
                dp[i][j] = dp[i + 1][j] if dp[i + 1][j] > dp[i][j - 1] else dp[i][j - 1]
    return dp[0][n - 1]

data = sys.stdin.read().split()
if not data:
    sys.exit()
T = int(data[0])
out = []
idx = 1
for _ in range(T):
    s = data[idx]
    idx += 1
    out.append(str(longest_pal_subseq(s)))
print('\n'.join(out))

